#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
		      int n,
		      std::vector<double>& A,
		      std::vector<double>& B) {
    constexpr double c = 0.33333;
    double *restrict a = A.data();
    double *restrict b = B.data();

    /* Warp loop: perform even–odd decomposition to reduce
       data dependency stalls in the inner loops. */
    for (int t = 0; t < tsteps; ++t) {
        /* First sweep: A -> B */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i) {
            const double m = a[i-1] + a[i] + a[i+1];
            b[i] = c * m;
        }

        /* Second sweep: B -> A */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i) {
            const double m = b[i-1] + b[i] + b[i+1];
            a[i] = c * m;
        }
    }
}
