#include <cmath>
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
		     std::vector<std::vector<double>>& A) {
    // Convert the 2‑D std::vector to a single 1‑D pointer for fast
    // index calculations and better cache behaviour.
    double *data = &A[0][0];          // assumes row-major contiguous layout

    // Parallelise the outer loop with OpenMP.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // j < i: off–diagonal entries
        for (int j = 0; j < i; ++j) {
            double *ptr_ij = data + i * n + j;   // &A[i][j]
            double sum = -(*ptr_ij);
            for (int k = 0; k < j; ++k) {
                sum -= data[i * n + k] * data[j * n + k];
            }
            *ptr_ij = sum / data[j * n + j];
        }

        // i == j: diagonal entry
        double *ptr_ii = data + i * n + i;   // &A[i][i]
        double sum = *ptr_ii;
        for (int k = 0; k < i; ++k) {
            sum -= data[i * n + k] * data[i * n + k];
        }
        *ptr_ii = std::sqrt(sum);
    }
}
