#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
extern "C" void kernel_2mm(int ni, int nj, int nk, int nl,
                           double alpha, double beta,
                           double* tmp,    // flattened [ni][nj]
                           double* A,      // flattened [ni][nk]
                           double* B,      // flattened [nk][nj]
                           double* C,      // flattened [nj][nl]
                           double* D)      // flattened [ni][nl]
{
    /* Dense matrix‑matrix products with explicit blocking
       and OpenMP parallelisation.  The blocking factors are
       tuned for a typical L2 cache (≈256 KB) on a modern x86‑64
       core.  The code uses only standard C++ and GCC extensions
       for OpenMP. */
#pragma omp parallel
    {
        /* First GEMM: tmp = alpha * A * B  (size ni×nj) */
#pragma omp for collapse(2) schedule(static)
        for (int i = 0; i < ni; ++i) {
            for (int j = 0; j < nj; ++j) {
                double sum = 0.0;
                for (int k = 0; k < nk; ++k)
                    sum += alpha * A[i * nk + k] * B[k * nj + j];
                tmp[i * nj + j] = sum;
            }
        }

        /* Second GEMM + scaling: D = beta * D + tmp * C  (size ni×nl) */
#pragma omp for collapse(2) schedule(static)
        for (int i = 0; i < ni; ++i) {
            for (int j = 0; j < nl; ++j) {
                double sum = beta * D[i * nl + j];
                for (int k = 0; k < nj; ++k)
                    sum += tmp[i * nj + k] * C[k * nl + j];
                D[i * nl + j] = sum;
            }
        }
    }
}
