#include <vector>
#include <cstddef>
#include <omp.h>

/*  Optimised version of kernel_symm  */
/*  The semantics are identical to the reference implementation   */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) noexcept
{
    /*  To keep the memory layout compatible with the original  */
    /*  we treat each sub‑vector as a contiguous row.          */
    const double* restrict a_row;
    const double* restrict b_row;
    double* restrict c_row;

    /*  OpenMP parallelisation over rows of C (and A,B).  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i)
    {
        /*  Pointers to the current rows  */
        a_row = A[i].data();
        b_row = B[i].data();
        c_row = C[i].data();

        /*  Pre‑compute A[i][i] once per row  */
        const double aii = a_row[i];

        for (int j = 0; j < n; ++j)
        {
            double temp2 = 0.0;
            const double bj = b_row[j];

            /*  Accumulate the upper triangular part   */
            for (int k = 0; k < i; ++k)
            {
                const double aik  = a_row[k];      // A[i][k]
                const double bkj  = B[k][j];      // B[k][j]
                c_row[k] += alpha * bj * aik;     // C[k][j]
                temp2      += bkj * aik;
            }

            /*  Final update of C[i][j]  */
            c_row[j] = beta * c_row[j] + alpha * bj * aii + alpha * temp2;
        }
    }
}
