/* Main computational kernel. The function signature is kept
   unchanged so that the harness can call it exactly as before. */
void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    /* Parallelise the outermost loop – each iteration works
       on a separate row of the matrix and has no data
       dependency with the others. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* ------------------ Left part of the decomposition
           (j < i) ---------------------------------------- */
        double* row_i = A[i].data();                  // pointer to the current row

        for (int j = 0; j < i; ++j) {
            double* row_j = A[j].data();              // pointer to the j‑th row
            double sum = 0.0;

            /* Inner k‑loop - compute the dot product of the
               first i columns of row i and row j.     */
            for (int k = 0; k < j; ++k) {
                sum += row_i[k] * A[k][j];             // A[k][j] accessed directly
            }
            row_i[j] -= sum;
            row_i[j] /= row_j[j];                      // divide by the pivot element
        }

        /* ------------------ Right part of the decomposition
           (j >= i) --------------------------------------- */
        for (int j = i; j < n; ++j) {
            double sum = 0.0;

            for (int k = 0; k < i; ++k) {
                sum += row_i[k] * A[k][j];
            }
            row_i[j] -= sum;
        }
    }
}
