/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    // Use raw pointers for fast access to the vectors
    double *restrict xb = b.data();
    double *restrict xx = x.data();

    for (int i = 0; i < n; ++i) {
        double val = xb[i];                     // start with the RHS
        const double *restrict Lrow = L[i].data();

        // Inner dot‑product with the current row of L
        // pragma to hint vectorisation
#pragma omp simd
        for (int j = 0; j < i; ++j) {
            val -= Lrow[j] * xx[j];
        }

        // Divide by the diagonal element
        xx[i] = val / Lrow[i];
    }
}
