#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* Parallelise over the outer loop (rows). */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        double tmp_i = 0.0;
        double y_i   = 0.0;

        /* Unroll inner loop in stretches of 4 for a small speedup */
        int j = 0;
        for (; j <= n - 4; j += 4)
        {
            tmp_i += A[i][j]     * x[j];
            y_i   += B[i][j]     * x[j];

            tmp_i += A[i][j + 1] * x[j + 1];
            y_i   += B[i][j + 1] * x[j + 1];

            tmp_i += A[i][j + 2] * x[j + 2];
            y_i   += B[i][j + 2] * x[j + 2];

            tmp_i += A[i][j + 3] * x[j + 3];
            y_i   += B[i][j + 3] * x[j + 3];
        }

        /* Handle the remaining elements */
        for (; j < n; ++j)
        {
            tmp_i += A[i][j] * x[j];
            y_i   += B[i][j] * x[j];
        }

        /* Final accumulation and store results */
        tmp[i] = tmp_i;
        y[i]   = alpha * tmp_i + beta * y_i;
    }
}
```
The code keeps the exact functional behaviour while:

* Parallelising the outer loop using OpenMP (`#pragma omp parallel for`).
* Using local registers (`tmp_i`, `y_i`) to avoid repeated memory accesses.
* Minor loop unrolling to reduce loop‑control overhead.
* Static scheduling gives balanced work distribution on 8 threads.

