            int* row_i = path[i].data();             // pointer to row i
            int* row_k = path[k].data();             // pointer to row k
            for (int j = 0; j < n; ++j) {
                int alt = row_i[k] + row_k[j];
                if (alt < row_i[j]) row_i[j] = alt;
            }
        }
    }
