#include <vector>
#include <algorithm>
#include <omp.h>

/*
  Optimized Nussinov kernel
  Parallelised over anti‑diagonals.
  Keeps behaviour identical to the reference implementation.
*/

#pragma GCC push_options
#pragma GCC optimize ("O3")   // ensure high optimisation

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    // Helper for base‑pairing rule
    auto match = [&](int a, int b) -> int {
        return (a + b == 3) ? 1 : 0;
    };

    // We fill the table along anti‑diagonals:
    // for each d = i + j (from 1 to 2*n-2), i ranges from max(0, d-(n-1)) to min(n-1, d-1)
    const int maxDiag = 2 * n - 2;
    for (int d = 1; d <= maxDiag; ++d) {
        // the number of rows in this diagonal
        int i_start = (d < n) ? 0 : d - (n - 1);
        int i_end   = (d < n) ? d - 1 : n - 1;

        // Parallelise over the rows in the current diagonal.
        #pragma omp parallel for schedule(static)
        for (int i = i_start; i <= i_end; ++i) {
            int j = d - i;                 // Since i + j = d
            int best = 0;

            // table[i][j] is already 0 by construction of the vector
            // but we follow the original algorithm for clarity.
            if (j - 1 >= 0)
                best = std::max(best, table[i][j - 1]);

            if (i + 1 < n)
                best = std::max(best, table[i + 1][j]);

            if (j - 1 >= 0 && i + 1 < n) {
                if (i < j - 1)
                    best = std::max(best, table[i + 1][j - 1] + match(seq[i], seq[j]));
                else
                    best = std::max(best, table[i + 1][j - 1]);
            }

            for (int k = i + 1; k < j; ++k)
                best = std::max(best, table[i][k] + table[k + 1][j]);

            table[i][j] = best;
        }
    }
}

#pragma GCC pop_options
