/* Optimised kernel ---------------------------------------------------------
 *  The behaviour is identical: for each (r,q) the vector A[r][q] is replaced
 *   by the product A[r][q] * C4 (matrix multiplication of size np×np).
 * -------------------------------------------------------------------------- */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum) {

    // ensure the auxiliary vector has the required size (np)
    if (static_cast<int>(sum.size()) < np)
        sum.resize(np);

    // Parallelisation over the outer two loops – a static schedule gives
    // excellent load balance when nr and nq are reasonably large.
    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            // local alias for the 1‑D slice of A (r,q,*)
            double* const Arq = A[r][q].data();
            // compute the product using a temporary sum vector
            for (int p = 0; p < np; ++p)
                sum[p] = 0.0;

#pragma omp simd
            for (int s = 0; s < np; ++s) {
                double val = A[r][q][s];
                const double* const C4s = C4[s].data();
                for (int p = 0; p < np; ++p)
                    sum[p] += val * C4s[p];
            }

            // copy result back to A[r][q]
#pragma omp simd
            for (int p = 0; p < np; ++p)
                Arq[p] = sum[p];
        }
    }
