```cpp
#include <numeric>
#include <vector>
#include <cmath>
#include <omp.h>

// The original kernel is unchanged in algorithmic function.  The
// parallelization and a few micro‑optimizations are added
// to obtain higher throughput on a modern x86‑64 CPU with 8 threads.
// Only strictly required headers are retained.

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    const double eps = 0.1;
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* 1.  Compute column means ------------------------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) s += data[i][j];
        mean[j] = s / n;
    }

    /* 2.  Compute column standard deviations -----------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        const double mj = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mj;
            s += d * d;
        }
        s /= n;
        stddev[j] = std::sqrt(s);
        if (stddev[j] <= eps) stddev[j] = 1.0;  // anti‑zero‑division
    }

    /* 3.  Center and scale the data ------------------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) * inv_sqrt_n / stddev[j];
        }
    }

    /* 4.  Compute correlation matrix ---------------------------------------*/
    // fill upper triangle and mirror
    for (int i = 0; i < m - 1; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k) {
                s += data[k][i] * data[k][j];
            }
            corr[i][j] = s;
            corr[j][i] = s;
        }
    }
    corr[m-1][m-1] = 1.0;
}
