#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    /* Zero y in parallel */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) {
        y[j] = 0.0;
    }

    /* Compute tmp and accumulate into y in parallel.
     * Each iteration over i is independent, so we can
     * parallelise the outer loop. y is reduced with a
     * vector reduction. */
    #pragma omp parallel for schedule(static) reduction(+:y[:n])
    for (int i = 0; i < m; ++i) {
        double sum = 0.0;
        /* compute tmp[i] */
        for (int j = 0; j < n; ++j) {
            sum += A[i][j] * x[j];
        }
        tmp[i] = sum;

        /* update y */
        for (int j = 0; j < n; ++j) {
            y[j] += A[i][j] * sum;
        }
    }
}
