#include <omp.h>

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    // Flatten the 2D vectors into 1D arrays for better cache locality
    std::vector<double> flat_data(static_cast<std::size_t>(n) * m);
    std::vector<double> flat_cov(static_cast<std::size_t>(m) * m);

    // Build flat data (column major for faster covariance evaluation)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            flat_data[i * m + j] = data[i][j];

    // 1. Compute column means
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += flat_data[i * m + j];
        mean[j] = sum / n;
    }

    // 2. Center the data
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            flat_data[i * m + j] -= mean[j];

    // 3. Compute upper triangular part of covariance matrix
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += flat_data[k * m + i] * flat_data[k * m + j];
            }
            double val = sum / (n - 1.0);
            flat_cov[i * m + j] = val;
            if (i != j) flat_cov[j * m + i] = val; // Fill symmetric element
        }
    }

    // Copy results back to the original containers (column major)
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < m; ++j)
            cov[i][j] = flat_cov[i * m + j];
}
