    A is passed as a vector of vectors; we convert it to a single
    contiguous block once for maximum spatial locality.  The outer
    dimension is parallelised with OpenMP.  The code is compiled with
    -O2 and -fopenmp. */
inline void to_flat(const std::vector<std::vector<double>>& A,
                    std::vector<double>& flat,
                    std::size_t n)
{
    flat.resize(n * n);
    for (std::size_t i = 0; i < n; ++i)
        std::copy(A[i].begin(), A[i].end(), flat.begin() + i * n);
}

void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A)
{
    // Flatten matrix A to 1‑D array for cache‑friendly access
    static thread_local std::vector<double> flatA;
    if (flatA.size() != static_cast<std::size_t>(n) * n)
        to_flat(A, flatA, n);

    const double *A_flat = flatA.data();
    const double *y1 = y_1.data();
    const double *y2 = y_2.data();
    double *x1_out = x1.data();
    double *x2_out = x2.data();

    const std::size_t N = static_cast<std::size_t>(n);

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        double sum1 = 0.0;
        const double *A_row = A_flat + i * N;          // A[i][*]
        for (std::size_t j = 0; j < N; ++j) {
            sum1 += A_row[j] * y1[j];
        }
        x1_out[i] += sum1;
    }

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        double sum2 = 0.0;
        for (std::size_t j = 0; j < N; ++j) {
            // A[j][i] -> A_flat + j*N + i
            sum2 += A_flat[j * N + i] * y2[j];
        }
        x2_out[i] += sum2;
    }
}
