/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    /*  A  : n × m  (row‑major)
        C  : n × n  (symmetric, only lower triangle used)
        The algorithm computes               C = α*A*Aᵀ + β*C
        it is written in a way that keeps the original
        loop order but is fully parallelised and cache‑friendly.   */

    /* ------------------------------------------------------------------
       1) Parallelisation:  Each outer i is independent, so we parallelise
          over it.  A dynamic schedule guarantees low load skew for
          small n.  The inner loops are kept serial because they
          are already very fast after compaction below.
     ------------------------------------------------------------------ */
#pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < n; ++i) {
        double* ci = C[i].data();               // pointer to row i
        const double* ai = A[i].data();         // pointer to row i of A

        /* 2) Scale the lower‑triangle part of C[i,*] by β. */
        for (int j = 0; j <= i; ++j)
            ci[j] *= beta;

        /* 3) Accumulate α * (A[i,⋅] · A[j,⋅]) over k and j.  */
        /*    To minimise pointer indirections we keep local pointers
            to the rows of A that we need in the inner j loop.          */
        for (int k = 0; k < m; ++k) {
            const double aik = ai[k];           // A[i][k]
            for (int j = 0; j <= i; ++j) {
                const double* aj = A[j].data();   // A[j,⋅]
                ci[j] += alpha * aik * aj[k];
            }
        }
    }
}
