#include <omp.h>

/* QR Decomposition with Modified Gram Schmidt
 * Optimised for Intel‑style x86‑64, GCC 9+ with -fopenmp -O2.
 * The interface is unchanged – the harness calls this function only.
 */
void kernel_gramschmidt(const int m, const int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q)
{
    // Work with raw pointers for better cache‑line utilisation
    double* A_ptr = &A[0][0];
    double* R_ptr = &R[0][0];
    double* Q_ptr = &Q[0][0];

    /* Helper: element access: idx(i,j) = i + j*m */
    auto idx = [m](int i, int j) noexcept { return i + j * m; };

    for (int k = 0; k < n; ++k) {
        /* 1. Compute ||A[:,k]|| : parallel reduction */
        double nrm = 0.0;
        #pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i)
            nrm += A_ptr[idx(i,k)] * A_ptr[idx(i,k)];
        const double rk = std::sqrt(nrm);
        R_ptr[idx(k,k)] = rk;

        /* 2. Normalise the k‑th column into Q */
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i)
            Q_ptr[idx(i,k)] = A_ptr[idx(i,k)] / rk;

        /* 3. Orthogonalise remaining columns */
        for (int j = k + 1; j < n; ++j) {
            double rkj = 0.0;

            /* R[k][j] = Q[:,k]^T * A[:,j] */
            #pragma omp parallel for reduction(+:rkj) schedule(static)
            for (int i = 0; i < m; ++i)
                rkj += Q_ptr[idx(i,k)] * A_ptr[idx(i,j)];
            R_ptr[idx(k,j)] = rkj;

            /* A[:,j] -= Q[:,k] * rkj */
            #pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                A_ptr[idx(i,j)] -= Q_ptr[idx(i,k)] * rkj;
            }
        }
    }
}
