#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z)
{
    /* 1. Rank‑1 updates on A: A = A + u1*v1^T + u2*v2^T
     * This is a classic outer product that can be collapsed to a
     * single parallel region with a 2‑D loop. */
#pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        double ui1 = u1[i];
        double ui2 = u2[i];
        for (int j = 0; j < n; ++j) {
            A[i][j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    /* 2. x = x + beta * A^T * y   (A transposed inner product)
     * Each thread updates a distinct slice of x; the product can
     * be performed row‑wise over the transposed matrix. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = x[i];
        for (int j = 0; j < n; ++j) {
            sum += beta * A[j][i] * y[j];
        }
        x[i] = sum;
    }

    /* 3. x = x + z */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    /* 4. w = w + alpha * A * x
     * Similar to step 1 but with a left‑multiplication. */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double wi = w[i];
        double ai_dot = 0.0;
        for (int j = 0; j < n; ++j) {
            ai_dot += A[i][j] * x[j];
        }
        wi += alpha * ai_dot;
        w[i] = wi;
    }
}
