    return &v[i][j];
}

/* Fused time‑domain finite‑difference kernel */
void kernel_fdtd_2d(int tmax,
                    int nx,
                    int ny,
                    std::vector<std::vector<double>>& ex,
                    std::vector<std::vector<double>>& ey,
                    std::vector<std::vector<double>>& hz,
                    std::vector<double>& _fict_) {
    const int stride = ny;                // row stride
    const int total = nx * ny;            // total elements per field

    /* Work on raw pointers for better cache behaviour */
    double *pex = &ex[0][0];
    double *pey = &ey[0][0];
    double *phz = &hz[0][0];
    double *pfict = _fict_.data();

    /* Use OpenMP parallelisation over time steps */
    #pragma omp parallel for schedule(static)
    for (int t = 0; t < tmax; ++t) {
        /* ey[0][:] = _fict_[t] */
        double f = pfict[t];
        for (int j = 0; j < ny; ++j)
            pey[j] = f;

        /* Update ey for rows i=1..nx-1 */
        for (int i = 1; i < nx; ++i) {
            double *ey_i   = pey + i * stride;
            double *hz_i   = phz + i * stride;
            double *hz_ip1 = phz + (i-1) * stride;
            for (int j = 0; j < ny; ++j)
                ey_i[j] -= 0.5 * (hz_i[j] - hz_ip1[j]);

            /* Barrier not needed: each i is independent */
        }

        /* Update ex for columns j=1..ny-1 */
        for (int i = 0; i < nx; ++i) {
            double *ex_i   = pex + i * stride;
            double *hz_i   = phz + i * stride;
            for (int j = 1; j < ny; ++j)
                ex_i[j] -= 0.5 * (hz_i[j] - hz_i[j-1]);
        }

        /* Update hz for interior cells */
        for (int i = 0; i < nx-1; ++i) {
            double *hz_i     = phz + i * stride;
            double *ex_i     = pex + i * stride;
            double *ey_ip1   = pey + (i+1) * stride;
            double *ey_i     = pey + i * stride;
            for (int j = 0; j < ny-1; ++j)
                hz_i[j] -= 0.7 * (ex_i[j+1] - ex_i[j] + ey_ip1[j] - ey_i[j]);
        }
    }
}
