// Helper to convert a 2‑D std::vector into a flat 1‑D array
inline double* vec2ptr(double& val) { return &val; }

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // Allocate flat buffers to improve spatial locality
    std::vector<double> a_flat(ni * nk);
    std::vector<double> b_flat(nk * nj);
    std::vector<double> c_flat(ni * nj);

    // Copy data from the 2D vectors into flat arrays
    for (int i = 0; i < ni; ++i)
        for (int k = 0; k < nk; ++k)
            a_flat[i * nk + k] = A[i][k];

    for (int k = 0; k < nk; ++k)
        for (int j = 0; j < nj; ++j)
            b_flat[k * nj + j] = B[k][j];

    for (int i = 0; i < ni; ++i)
        for (int j = 0; j < nj; ++j)
            c_flat[i * nj + j] = C[i][j];

    // Parallel GEMM: C = alpha*A*B + beta*C
    const int outer_block = 64;     // tune for your cache
    const int inner_block = 32;     // tune for your cache

    // Scale C by beta once outside of the inner loops
    #pragma omp parallel for schedule(static, outer_block)
    for (int i = 0; i < ni; i += outer_block) {
        int i_end = std::min(i + outer_block, ni);
        for (int ii = i; ii < i_end; ++ii) {
            double* c_row = &c_flat[ii * nj];
            for (int j = 0; j < nj; ++j) {
                c_row[j] *= beta;
            }
        }
    }

    // Main fused multiply‑add
    #pragma omp parallel for collapse(2) schedule(static, outer_block)
    for (int i = 0; i < ni; i += outer_block) {
        int i_end = std::min(i + outer_block, ni);
        for (int j = 0; j < nj; j += inner_block) {
            int j_end = std::min(j + inner_block, nj);
            for (int ii = i; ii < i_end; ++ii) {
                double* a_row = &a_flat[ii * nk];
                double* c_row = &c_flat[ii * nj];
                for (int jj = j; jj < j_end; ++jj) {
                    double sum = 0.0;
                    for (int k = 0; k < nk; ++k) {
                        sum += a_row[k] * b_flat[k * nj + jj];
                    }
                    c_row[jj] += alpha * sum;
                }
            }
        }
    }

    // Copy back results to the original 2‑D vector
    for (int i = 0; i < ni; ++i)
        for (int j = 0; j < nj; ++j)
            C[i][j] = c_flat[i * nj + j];
}
