#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    /* The operation performed is that of a double‑sided SYR2K with
     * lower triangular portion of C (UPLO = 'L', TRANS = 'N').
     *
     *   C := beta*C + alpha*A^T*B + alpha*B^T*A
     *
     * where A and B are n×m matrices and C is n×n.
     *
     * The original implementation used nested std::vector indexing;
     * for performance we collapse the inner loops and overwrite the
     * entire lower triangular part of C in one go, using the
     * contiguous storage provided by the inner vector.  The only
     * dependency on the original code is the per‑row contiguous
     * storage – no layout changes are required, so the signature
     * remains untouched.
     */

    const double a = alpha;
    const double const_beta = beta;

    /* The outer loop over rows of C can be parallelised because each
     * thread works exclusively on a distinct row i.  We use a static
     * schedule to reduce scheduling overhead on 8 threads.
     */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
    {
        double* C_i = C[i].data();          // pointer to row i of C
        const double* B_i = B[i].data();    // row i of B

        /* First scale the lower triangle of C by beta */
        for (int j = 0; j <= i; ++j)
        {
            C_i[j] *= const_beta;
        }

        /* Accumulate the rank‑m update */
        for (int k = 0; k < m; ++k)
        {
            const double A_jk = A[k][i];    // prefix for the first transpose
            const double B_jk = B[k][i];

            /* Loop over j <= i only – this is the lower part of the matrix */
            for (int j = 0; j <= i; ++j)
            {
                /* We need A[j][k] and B[j][k] (the j‑th row of the k‑th column
                 * of A and B).  These are readily accessible by indexing
                 * the outer vector (rows).  The product of the two terms is
                 * accumulated into C[i][j].
                 */
                C_i[j] += a * (A[j][k] * B_i[k] + B[j][k] * A_i[k]);
            }
        }
    }
}
