#include <omp.h>

/* main computational kernel – identical interface and semantics */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
                std::vector<std::vector<double>>& E,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& F,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D,
                std::vector<std::vector<double>>& G)
{
    /* 3mm = 3 matrix multiplications chained together
     *    E = A * B           (ni × nj)
     *    F = C * D           (nj × nl)
     *    G = E * F           (ni × nl)
     *
     * All input matrices are assumed to be contiguous row‑major
     * vectors of vectors, i.e. E[i][j] == (&E[0][0])[i*nj + j]
     *
     * We exploit OpenMP parallelism on the outermost loop and
     * use cache‑friendly accesses.
     */

    /* --------------------------------------------------------------------
     * 1st multiplication: E = A * B  (ni × nj)
     * -------------------------------------------------------------------- */
#pragma omp parallel for schedule(static, 64)
    for (int i = 0; i < ni; ++i)
    {
        double* restrict ei = &E[i][0];
        const double* restrict Ai = &A[i][0];

        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double* restrict Bj = &B[0][j];
            for (int k = 0; k < nk; ++k) {
                sum += Ai[k] * Bj[k];
            }
            ei[j] = sum;
        }
    }

    /* --------------------------------------------------------------------
     * 2nd multiplication: F = C * D  (nj × nl)
     * -------------------------------------------------------------------- */
#pragma omp parallel for schedule(static, 64)
    for (int i = 0; i < nj; ++i)
    {
        double* restrict fi = &F[i][0];
        const double* restrict Ci = &C[i][0];

        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double* restrict Dj = &D[0][j];
            for (int k = 0; k < nm; ++k) {
                sum += Ci[k] * Dj[k];
            }
            fi[j] = sum;
        }
    }

    /* --------------------------------------------------------------------
     * 3rd multiplication: G = E * F  (ni × nl)
     * -------------------------------------------------------------------- */
#pragma omp parallel for schedule(static, 64)
    for (int i = 0; i < ni; ++i)
    {
        double* restrict gi = &G[i][0];
        const double* restrict ei = &E[i][0];

        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double* restrict fj = &F[0][j];
            for (int k = 0; k < nj; ++k) {
                sum += ei[k] * fj[k];
            }
            gi[j] = sum;
        }
    }
}
