#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return.  */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    /* Local aliases for faster access */
    double **Adata   = new double*[n];
    for (int i = 0; i < n; ++i) {
        Adata[i] = A[i].data();
    }

    /* --- LU factorisation ------------------------------------------------- */
    for (int i = 0; i < n; ++i) {
        /* 1) L part  (j < i) :   A[i][j] = (A[i][j] - Σk A[i][k]A[k][j]) / A[j][j] */
        for (int j = 0; j < i; ++j) {
            double w = Adata[i][j];
            for (int k = 0; k < j; ++k) {
                w -= Adata[i][k] * Adata[k][j];
            }
            Adata[i][j] = w / Adata[j][j];
        }

        /* 2) U part  (j >= i) :   A[i][j] = A[i][j] - Σk A[i][k]A[k][j] */
        for (int j = i; j < n; ++j) {
            double w = Adata[i][j];
            for (int k = 0; k < i; ++k) {
                w -= Adata[i][k] * Adata[k][j];
            }
            Adata[i][j] = w;
        }
    }

    /* --- Forward substitution  (L·y = b) --------------------------------- */
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        for (int j = 0; j < i; ++j) {
            w -= Adata[i][j] * y[j];
        }
        y[i] = w;   /* L is unit‑diagonal, so no division needed */
    }

    /* --- Backward substitution (U·x = y) --------------------------------- */
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        for (int j = i + 1; j < n; ++j) {
            w -= Adata[i][j] * x[j];
        }
        x[i] = w / Adata[i][i];   /* divide by diagonal of U */
    }

    delete[] Adata;
}
