#include <cmath>
#include <cstddef>
#include <vector>
#include <algorithm>
#include <xtensor/xsimd.hpp>   // Use Xsimd for portable SIMD (openmp not needed for this kernel)

void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    // Ensure y has size n
    if (static_cast<int>(y.size()) < n) y.resize(n);

    // Working buffer z reused every iteration
    std::vector<double> z(n);

    // Pointers to raw data for speed
    const double* rptr = r.data();
    double* yptr     = y.data();
    double* zptr     = z.data();

    yptr[0] = -rptr[0];
    double beta  = 1.0;
    double alpha = -rptr[0];

    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        // Compute sum = Σ_{i=0}^{k-1} r[k-i-1] * y[i]
        double sum = 0.0;
        int i = 0;
#if defined(__AVX2__) && defined(__FMA__)
        const int simd_step = 4;  // 4 doubles per 256‑bit vector
        __m256d vsum = _mm256_setzero_pd();
        for (; i <= k - simd_step; i += simd_step) {
            __m256d vr = _mm256_setr_pd(rptr[k-1-i], rptr[k-2-i], rptr[k-3-i], rptr[k-4-i]);
            __m256d vy = _mm256_loadu_pd(yptr + i);
            vsum = _mm256_fmadd_pd(vr, vy, vsum);
        }
        sum = _mm256_reduce_add_pd(vsum);
#else
        for (; i < k; ++i) {
            sum += rptr[k - i - 1] * yptr[i];
        }
#endif
        alpha = -(rptr[k] + sum) / beta;

        // z[i] = y[i] + alpha * y[k-i-1]
#if defined(__AVX2__) && defined(__FMA__)
        i = 0;
        for (; i <= k - simd_step; i += simd_step) {
            __m256d vy1 = _mm256_loadu_pd(yptr + i);
            __m256d vy2 = _mm256_broadcast_sd(&yptr[k - i - 1]);  // load scalar then broadcast
            __m256d va  = _mm256_set1_pd(alpha);
            __m256d vz  = _mm256_fmadd_pd(va, vy2, vy1);
            _mm256_storeu_pd(zptr + i, vz);
        }
        for (; i < k; ++i) {
            zptr[i] = yptr[i] + alpha * yptr[k - i - 1];
        }
#else
        for (i = 0; i < k; ++i) {
            zptr[i] = yptr[i] + alpha * yptr[k - i - 1];
        }
#endif

        // Copy z back to y[0..k-1]
        std::copy(zptr, zptr + k, yptr);

        yptr[k] = alpha;
    }
}
