void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r) {
    /* --------------------------------------------------------------------
       1. Zero out the result vectors.
       2. Perform the BiCG kernel:
              s[j] += r[i] * A[i][j]
              q[i] += A[i][j] + p[j]
       -------------------------------------------------------------------- */

    /* 1. Zero the vectors in a single scan (cache friendly). */
    for (int i = 0; i < m; ++i) {
        s[i] = 0.0;
    }
    for (int i = 0; i < n; ++i) {
        q[i] = 0.0;
    }

    /* 2. Compute the kernel.  Two nested loops are required:
         - The outer loop over i (rows of A)
         - The inner loop over j (columns of A)

       Because the update of s[j] is performed by all rows, the
       computation is embarrassingly parallel along the rows.
       We use OpenMP to parallelise the outer loop, reducing cache
       misses by storing a thread‑local copy of the partial sums for s.
    */
    std::vector<std::vector<double>> s_local(omp_get_max_threads(),
                                             std::vector<double>(m, 0.0));

#pragma omp parallel
    {
        int tid = omp_get_thread_num();
        const int num_threads = omp_get_num_threads();

        /* Thread‑private local copy of s. */
        std::vector<double> &s_loc = s_local[tid];

        /* Loop over rows assigned to this thread. */
#pragma omp for schedule(static)
        for (int i = 0; i < n; ++i) {
            double *Ai  = A[i].data();   // pointer to the i‑th row
            double r_i  = r[i];          // cache this value
            double *q_row = &q[i];

            /* Update q[i] accordingly. */
            double q_val = 0.0;
            for (int j = 0; j < m; ++j) {
                q_val += Ai[j] + p[j];
                s_loc[j] += r_i * Ai[j];
            }
            q[i] = q_val;
        }
    }

    /* Fold the thread‑local s accumulators into the global vector. */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (size_t t = 0; t < s_local.size(); ++t) {
            sum += s_local[t][j];
        }
        s[j] = sum;
    }
}
