#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B) {
    constexpr double coef = 0.125;          // 1/8
    const int last = n - 1;                 // upper bound exclusive
    for (int t = 0; t < tsteps; ++t) {

        /* Update B from A */
#pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < last; ++i) {
            for (int j = 1; j < last; ++j) {
                for (int k = 1; k < last; ++k) {
                    const double a = A[i][j][k];

                    /* sum of the six neighbours */
                    double sum = A[i + 1][j][k] + A[i - 1][j][k]
                               + A[i][j + 1][k] + A[i][j - 1][k]
                               + A[i][j][k + 1] + A[i][j][k - 1];

                    /* Laplacian approximation + identity term */
                    B[i][j][k] = (sum - 6.0 * a) * coef + a;
                }
            }
        }

        /* Update A from B */
#pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < last; ++i) {
            for (int j = 1; j < last; ++j) {
                for (int k = 1; k < last; ++k) {
                    const double b = B[i][j][k];

                    double sum = B[i + 1][j][k] + B[i - 1][j][k]
                               + B[i][j + 1][k] + B[i][j - 1][k]
                               + B[i][j][k + 1] + B[i][j][k - 1];

                    A[i][j][k] = (sum - 6.0 * b) * coef + b;
                }
            }
        }
    }
}
