#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A,
		      std::vector<std::vector<double>>& B)
{
    /* stride between two rows */
    const std::ptrdiff_t stride = n;

    /* we keep the original two‑stage scheme (odd/even update) */
    for (int t = 0; t < tsteps; ++t) {

        /* ---------- stage 1 : A → B ----------
           OpenMP distributes the outer i‑loop among the threads.
           We keep j as the innermost loop for the best spatial locality. */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            double* Ai   = &A[i][0];
            double* Aim1 = &A[i-1][0];
            double* Aim1p1 = &A[i+1][0];
            double* Bi   = &B[i][0];
            double* Bip1 = &B[i+1][0];
            double* Bio1 = &B[i-1][0];

            /* inner loop unrolled by 4 to reduce loop overhead */
            int j = 1;
            const int jend = n - 1;
            for (; j <= jend - 3; j += 4) {
                Bi[j]   = 0.2 * (Ai[j]   + Ai[j-1] + Ai[j+1] + Aim1p1[j] + A[i][j-1]);
                Bi[j+1] = 0.2 * (Ai[j+1] + Ai[j]   + Ai[j+2] + Aim1p1[j+1] + A[i][j]);
                Bi[j+2] = 0.2 * (Ai[j+2] + Ai[j+1] + Ai[j+3] + Aim1p1[j+2] + A[i][j+1]);
                Bi[j+3] = 0.2 * (Ai[j+3] + Ai[j+2] + Ai[j+4] + Aim1p1[j+3] + A[i][j+2]);
            }
            for (; j < jend; ++j) {
                Bi[j] = 0.2 * (Ai[j] + Ai[j-1] + Ai[j+1] + Aim1p1[j] + A[i][j-1]);
            }
        }

        /* ---------- stage 2 : B → A ----------
           Identical structure to stage 1, but operating on B→A. */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            double* Bi   = &B[i][0];
            double* Bim1 = &B[i-1][0];
            double* Bip1 = &B[i+1][0];
            double* Ai   = &A[i][0];
            double* Aim1 = &A[i-1][0];

            int j = 1;
            const int jend = n - 1;
            for (; j <= jend - 3; j += 4) {
                Ai[j]   = 0.2 * (Bi[j]   + Bi[j-1] + Bi[j+1] + Bip1[j] + Bim1[j]);
                Ai[j+1] = 0.2 * (Bi[j+1] + Bi[j]   + Bi[j+2] + Bip1[j+1] + Bim1[j+1]);
                Ai[j+2] = 0.2 * (Bi[j+2] + Bi[j+1] + Bi[j+3] + Bip1[j+2] + Bim1[j+2]);
                Ai[j+3] = 0.2 * (Bi[j+3] + Bi[j+2] + Bi[j+4] + Bip1[j+3] + Bim1[j+3]);
            }
            for (; j < jend; ++j) {
                Ai[j] = 0.2 * (Bi[j] + Bi[j-1] + Bi[j+1] + Bip1[j] + Bim1[j]);
            }
        }
    }
