#include <algorithm>
#include <vector>
#include <cmath>
#include <cstddef>
#include <omp.h>

/* Replace the original std::vector of vectors with a 1‑D flat layout.
   The helper macros map 2‑D indices (i,j) into the flat buffer.
   All operations are unchanged, so the observable behaviour is identical.
   Parallelisation is achieved with OpenMP parallel loops.
*/
template <typename T>
inline T& idx(std::vector<T>& buf, std::size_t i, std::size_t j, std::size_t n)
{
    return buf[i * n + j];
}

void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u_vec,
                std::vector<std::vector<double>>& v_vec,
                std::vector<std::vector<double>>& p_vec,
                std::vector<std::vector<double>>& q_vec)
{
    /* Flatten the 2‑D vectors into 1‑D buffers for maximum locality. */
    std::vector<double> u(n * n), v(n * n), p(n * n), q(n * n);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j) {
            u[i * n + j] = u_vec[i][j];
            v[i * n + j] = v_vec[i][j];
            p[i * n + j] = p_vec[i][j];
            q[i * n + j] = q_vec[i][j];
        }

    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0, B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);

    const double a = -mul1 / 2.0;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 / 2.0;
    const double e = 1.0 + mul2;
    const double f = d;

    /* Main time‑step loop. The inner i‑loop is parallelised.
       The two lateral sweeps are independent so they can be
       executed one after the other. */
    for (int t = 1; t <= tsteps; ++t) {

        /* Forward sweep for v */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            v[0 * n + i] = 1.0;
            p[0 * n + i] = 0.0;
            q[0 * n + i] = v[0 * n + i];

            /* inner j loop */
            for (int j = 1; j < n - 1; ++j) {
                double denom = a * p[(j - 1) * n + i] + b;
                p[j * n + i] = -c / denom;
                denom = a * p[(j - 1) * n + i] + b;  // same denom
                double ujm = u[j * n + (i - 1)];
                double uj  = u[j * n + i];
                double ujp = u[j * n + (i + 1)];
                double qjm = q[(j - 1) * n + i];
                q[j * n + i] = (-d * ujm + (1.0 + 2.0 * d) * uj
                                - f * ujp - a * qjm) / denom;
            }

            v[(n - 1) * n + i] = 1.0;

            /* backward sweep for v */
            for (int j = n - 2; j >= 1; --j) {
                v[j * n + i] = p[j * n + i] * v[(j + 1) * n + i] + q[j * n + i];
            }
        }

        /* Forward sweep for u */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            u[i * n + 0] = 1.0;
            p[i * n + 0] = 0.0;
            q[i * n + 0] = u[i * n + 0];

            for (int j = 1; j < n - 1; ++j) {
                double denom = d * p[i * n + (j - 1)] + e;
                p[i * n + j] = -f / denom;
                denom = d * p[i * n + (j - 1)] + e; // same denom
                double v1 = v[(i - 1) * n + j];
                double v0 = v[i * n + j];
                double v2 = v[(i + 1) * n + j];
                double qjm = q[i * n + (j - 1)];
                q[i * n + j] = (-a * v1 + (1.0 + 2.0 * a) * v0
                                - c * v2 - d * qjm) / denom;
            }

            u[i * n + (n - 1)] = 1.0;

            for (int j = n - 2; j >= 1; --j) {
                u[i * n + j] = p[i * n + j] * u[i * n + (j + 1)] + q[i * n + j];
            }
        }
    }

    /* Copy results back into the original 2‑D vectors to preserve
       the exact external interface. */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j) {
            u_vec[i][j] = u[i * n + j];
            v_vec[i][j] = v[i * n + j];
            p_vec[i][j] = p[i * n + j];
            q_vec[i][j] = q[i * n + j];
        }
}
